/**
 * utils-merge
 *
 * Merges the properties from a source object into a destination object.
 *
 * This utility is used by Express.js for configuration management and middleware functionality.
 * It performs a shallow copy of properties from the source object to the destination object.
 *
 * @param {Object} dest - The destination object to merge properties into
 * @param {Object} src - The source object to merge properties from
 * @return {Object} The destination object with merged properties
 * @api public
 */

/**
 * Merge object b with object a.
 *
 * @param {Object} a - Destination object
 * @param {Object} b - Source object
 * @return {Object} a - The modified destination object
 * @api public
 */
exports = module.exports = function merge(a, b) {
  if (a && b) {
    for (var key in b) {
      a[key] = b[key];
    }
  }
  
  return a;
};